+                .expect("packet_id must be present");
+            let suite_id = value
+                .get("suite_id")
+                .and_then(serde_json::Value::as_str)
+                .expect("suite_id must be present");
+            match packet_id {
+                "FT-P2C-001" if matches!(suite_id, "scalar_dac" | "tensor_meta") => {
+                    saw_ft_p2c_001 = true;
